func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount == 0 || len(dess) != orderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	for orderIdx := 0; orderIdx < orderCount; orderIdx++ {
		ori := oris[orderIdx]
		des := dess[orderIdx]
		shipID := total_ship + orderIdx
		bestAssignIdx := -1
		bestCostDelta := math.MaxFloat64
		baseCosts := make([]float64, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			assign := &dispatch.Assigns[i]
			baseCosts[i] = assign.Cost
			if assign.AddShip(shipID, ori, des) {
				assign.GenRoute()
				newCost := assign.Cost
				costDelta := newCost - baseCosts[i]
				if newCost >= 0 && costDelta >= 0 && costDelta < bestCostDelta {
					bestCostDelta = costDelta
					bestAssignIdx = i
				}
				assign.RemoveShip(shipID)
				assign.GenRoute()
			}
		}
		if bestAssignIdx >= 0 {
			target := &dispatch.Assigns[bestAssignIdx]
			target.AddShip(shipID, ori, des)
			target.GenRoute()
